content:
{
  "sentences": [
    {
      "text": "這件上衣的顏色太深了，有沒有淺一點的？",
      "pinyin": "Zhè jiàn shàngyī de yánsè tài shēn le, yǒu méiyǒu qiǎn yīdiǎn de?",
      "pinyin_numeric": "zhe4 jian4 shang4yi1 de5 yan2se4 tai4 shen1 le5, you3 mei2you3 qian3 yi1dian3 de5?",
      "translation_en": "The color of this top is too dark; do you have a lighter one?",
      "translation_ko": "이 상의의 색상이 너무 진한데, 더 연한 게 있나요?"
    },
    {
      "text": "這條褲子太長了，可以幫我改短嗎？",
      "pinyin": "Zhè tiáo kùzi tài cháng le, kěyǐ bāng wǒ gǎi duǎn ma?",
      "pinyin_numeric": "zhe4 tiao2 ku4zi5 tai4 chang2 le5, ke3yi3 bang1 wo3 gai3 duan3 ma0?",
      "translation_en": "These pants are too long; can you help me shorten them?",
      "translation_ko": "이 바지가 너무 긴데, 짧게 수선해 주실 수 있나요?"
    },
    {
      "text": "這雙鞋子太小了，有大一點的尺寸嗎？",
      "pinyin": "Zhè shuāng xiézi tài xiǎo le, yǒu dà yīdiǎn de chǐcùn ma?",
      "pinyin_numeric": "zhe4 shuang1 xie2zi5 tai4 xiao3 le5, you3 da4 yi1dian3 de5 chi3cun4 ma0?",
      "translation_en": "These shoes are too small; do you have a larger size?",
      "translation_ko": "이 신발이 너무 작은데, 더 큰 사이즈가 있나요?"
    },
    {
      "text": "這件外套的尺寸太大了，我想試穿中號。",
      "pinyin": "Zhè jiàn wàitào de chǐcùn tài dà le, wǒ xiǎng shìchuān zhōng hào.",
      "pinyin_numeric": "zhe4 jian4 wai4tao4 de5 chi3cun4 tai4 da4 le5, wo3 xiang3 shi4chuan1 zhong1 hao4.",
      "translation_en": "The size of this jacket is too big; I want to try on a medium.",
      "translation_ko": "이 재킷의 사이즈가 너무 큰데, 중간 사이즈를 입어보고 싶어요."
    },
    {
      "text": "這件裙子太貴了，可以打折嗎？",
      "pinyin": "Zhè jiàn qúnzi tài guì le, kěyǐ dǎzhé ma?",
      "pinyin_numeric": "zhe4 jian4 qun2zi5 tai4 gui4 le5, ke3yi3 da3zhe2 ma0?",
      "translation_en": "This skirt is too expensive; can it be discounted?",
      "translation_ko": "이 치마가 너무 비싼데, 할인해 주실 수 있나요?"
    },
    {
      "text": "這件上衣的材質太厚了，夏天穿會很熱。",
      "pinyin": "Zhè jiàn shàngyī de cáizhí tài hòu le, xiàtiān chuān huì hěn rè.",
      "pinyin_numeric": "zhe4 jian4 shang4yi1 de5 cai2zhi2 tai4 hou4 le5, xia4tian1 chuan1 hui4 hen3 re4.",
      "translation_en": "The material of this top is too thick; it will be very hot to wear in summer.",
      "translation_ko": "이 상의의 소재가 너무 두꺼워서 여름에 입으면 더울 거예요."
    },
    {
      "text": "這件褲子的顏色太淺了，我比較喜歡深藍色。",
      "pinyin": "Zhè jiàn kùzi de yánsè tài qiǎn le, wǒ bǐjiào xǐhuān shēn lán sè.",
      "pinyin_numeric": "zhe4 jian4 ku4zi5 de5 yan2se4 tai4 qian3 le5, wo3 bi3jiao4 xi3huan1 shen1 lan2 se4.",
      "translation_en": "The color of these pants is too light; I prefer dark blue.",
      "translation_ko": "이 바지의 색상이 너무 연한데, 저는 진한 파란색을 더 좋아해요."
    },
    {
      "text": "這雙襪子太薄了，我想要厚一點的。",
      "pinyin": "Zhè shuāng wàzi tài báo le, wǒ xiǎng yào hòu yīdiǎn de.",
      "pinyin_numeric": "zhe4 shuang1 wa4zi5 tai4 bao2 le5, wo3 xiang3 yao4 hou4 yi1dian3 de5.",
      "translation_en": "These socks are too thin; I want thicker ones.",
      "translation_ko": "이 양말이 너무 얇은데, 더 두꺼운 걸 원해요."
    },
    {
      "text": "這件外套的顏色太亮了，有沒有暗一點的？",
      "pinyin": "Zhè jiàn wàitào de yánsè tài liàng le, yǒu méiyǒu àn yīdiǎn de?",
      "pinyin_numeric": "zhe4 jian4 wai4tao4 de5 yan2se4 tai4 liang4 le5, you3 mei2you3 an4 yi1dian3 de5?",
      "translation_en": "The color of this jacket is too bright; do you have a darker one?",
      "translation_ko": "이 재킷의 색상이 너무 밝은데, 더 어두운 게 있나요?"
    },
    {
      "text": "這件裙子的尺寸太小了，可以換大一點的嗎？",
      "pinyin": "Zhè jiàn qúnzi de chǐcùn tài xiǎo le, kěyǐ huàn dà yīdiǎn de ma?",
      "pinyin_numeric": "zhe4 jian4 qun2zi5 de5 chi3cun4 tai4 xiao3 le5, ke3yi3 huan4 da4 yi1dian3 de5 ma0?",
      "translation_en": "The size of this skirt is too small; can I exchange it for a larger one?",
      "translation_ko": "이 치마의 사이즈가 너무 작은데, 더 큰 걸로 교환할 수 있나요?"
    }
  ]
}
